import{_ as a,o as t,c as r,a7 as i}from"./chunks/framework.C5fSpjcB.js";const m=JSON.parse('{"title":"Card Upgrades","description":"","frontmatter":{},"headers":[],"relativePath":"en/cards/upgrade.md","filePath":"en/cards/upgrade.md","lastUpdated":1775394001000}'),d={name:"en/cards/upgrade.md"};function s(o,e,l,n,c,p){return t(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="card-upgrades" tabindex="-1">Card Upgrades <a class="header-anchor" href="#card-upgrades" aria-label="Permalink to &quot;Card Upgrades&quot;">​</a></h1><p>Every card in Morimens can be upgraded up to <strong>6 times</strong>, progressively increasing its power, modifying its effects, or reducing its Arithmetica cost.</p><h2 id="upgrade-levels" tabindex="-1">Upgrade Levels <a class="header-anchor" href="#upgrade-levels" aria-label="Permalink to &quot;Upgrade Levels&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Level</th><th>Effect</th></tr></thead><tbody><tr><td>Base (Lv 0)</td><td>Default card stats and effects</td></tr><tr><td>Lv 1</td><td>Minor stat increase</td></tr><tr><td>Lv 2</td><td>Stat increase or minor effect enhancement</td></tr><tr><td>Lv 3</td><td>Notable power spike; may add secondary effects</td></tr><tr><td>Lv 4</td><td>Significant enhancement</td></tr><tr><td>Lv 5</td><td>Major power increase</td></tr><tr><td>Lv 6 (Max)</td><td>Maximum power; may transform the card&#39;s effect or add a new mechanic</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Upgrade Level 3 and Level 6 are common breakpoints where cards gain qualitative improvements (new effects) rather than just numerical buffs. Prioritize reaching these thresholds.</p></div><h2 id="upgrade-materials" tabindex="-1">Upgrade Materials <a class="header-anchor" href="#upgrade-materials" aria-label="Permalink to &quot;Upgrade Materials&quot;">​</a></h2><p>Card upgrades require materials obtained from:</p><ul><li><a href="./../stages/resource.html">Resource Stages</a></li><li><a href="./../modes/investigation.html">Investigation</a> rewards</li><li>Event shops</li><li><a href="./../modes/smelting.html">Smelting Room</a> crafting</li></ul><p><em>Specific material names and quantities to be added.</em></p><h2 id="upgrade-priority" tabindex="-1">Upgrade Priority <a class="header-anchor" href="#upgrade-priority" aria-label="Permalink to &quot;Upgrade Priority&quot;">​</a></h2><ol><li><strong>Main DPS Command Cards</strong> — Maximize your primary damage dealer&#39;s output first.</li><li><strong>Spirit Awakening Cards</strong> — High-impact abilities benefit greatly from upgrades.</li><li><strong>Support utility cards</strong> — Upgraded heals and buffs scale your whole team.</li><li><strong>Tank defensive cards</strong> — Lower priority but valuable for hard content.</li></ol><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Card upgrade materials are limited, especially early on. Do not spread upgrades evenly across all cards. Focus on your core team&#39;s most impactful cards first.</p></div><h2 id="how-upgrades-affect-deckbuilding" tabindex="-1">How Upgrades Affect Deckbuilding <a class="header-anchor" href="#how-upgrades-affect-deckbuilding" aria-label="Permalink to &quot;How Upgrades Affect Deckbuilding&quot;">​</a></h2><p>Upgraded cards can change the optimal way to play a deck. A card that is mediocre at Lv 0 may become a core combo piece at Lv 6. Re-evaluate your <a href="./deckbuilding.html">deck composition</a> as you upgrade key cards.</p><h2 id="see-also" tabindex="-1">See Also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See Also&quot;">​</a></h2><ul><li><a href="./">Card System Overview</a></li><li><a href="./list.html">Card List</a></li><li><a href="./deckbuilding.html">Deckbuilding Guide</a></li><li><a href="./../stages/resource.html">Resource Stages</a></li></ul>',16)])])}const h=a(d,[["render",s]]);export{m as __pageData,h as default};
